{
  "title": "हाइब्रिड खोज",
  "group": "पुनर्प्राप्ति",
  "options": [
    {
      "text": "अतिरेक के लिए एक ही क्वेरी को दो बार चलाना"
    },
    {
      "text": "एक ही कॉर्पस पर दो अलग-अलग एम्बेडिंग मॉडल का उपयोग करना"
    },
    {
      "text": "बेहतर पुनर्प्राप्ति के लिए वेक्टर खोज को कीवर्ड खोज के साथ संयोजित करना"
    },
    {
      "text": "एक साथ कई वेक्टर डेटाबेस में खोज करना"
    }
  ],
  "questionProse": [
    "RAG सिस्टम में, \"हाइब्रिड खोज\" का तात्पर्य है:"
  ],
  "explanationProse": [
    "हाइब्रिड खोज **वेक्टर खोज** (एम्बेडिंग के माध्यम से अर्थगत समानता) और **कीवर्ड खोज** (BM25 / पूर्ण-पाठ खोज) को जोड़ती है क्योंकि ये पूरक तरीकों से विफल होते हैं:\n\n    - वेक्टर खोज सटीक शब्दों के साथ संघर्ष करती है: उत्पाद नाम, त्रुटि कोड, मॉडल नंबर, तकनीकी पहचानकर्ता\n    - कीवर्ड खोज व्याख्या के साथ संघर्ष करती है: \"मैं कैसे रद्द करूं\" बनाम \"सदस्यता समाप्त करें\"\n\n    दोनों के परिणाम **रिसिप्रोकल रैंक फ्यूज़न (RRF)** का उपयोग करके संयोजित किए जाते हैं — एक रैंकिंग एल्गोरिदम जो सामान्यीकृत स्कोर की आवश्यकता के बिना कई रैंक की गई सूचियों से स्थितियों को जोड़ता है।\n\n    दोनों Postgres में `pgvector` + `tsvector` के साथ उपलब्ध हैं। आपको एक अलग खोज सेवा की आवश्यकता नहीं हो सकती है।"
  ]
}
